import{_ as t,o as a,c as s,ae as i}from"./chunks/framework.BMBGeRFM.js";const k=JSON.parse('{"title":"Crate of The Week!","description":"","frontmatter":{"title":"Crate of The Week!","date":"2026-05-12T00:00:00.000Z"},"headers":[],"relativePath":"news/2026-05-12-crate-of-the-week.md","filePath":"news/2026-05-12-crate-of-the-week.md"}'),n={name:"news/2026-05-12-crate-of-the-week.md"};function o(r,e,h,l,d,p){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="farben-is-crate-of-the-week-in-this-week-in-rust-648" tabindex="-1">Farben is &quot;Crate of the Week&quot; in This Week in Rust #648! <a class="header-anchor" href="#farben-is-crate-of-the-week-in-this-week-in-rust-648" aria-label="Permalink to &quot;Farben is &quot;Crate of the Week&quot; in This Week in Rust #648!&quot;">​</a></h1><p>This Week in Rust issue #648 is at <em>April 22, 2026</em>. Check out the new sick badge at the README!</p><hr><p>Well, this one came out of nowhere.</p><p>Farben was just named <strong>Crate of the Week</strong> in <a href="https://this-week-in-rust.org/blog/2026/04/22/this-week-in-rust-648/" target="_blank" rel="noreferrer">This Week in Rust #648</a>, one of the most widely-read newsletters in the Rust community. I found out the same way most of you probably did: by reading TWiR like any other week, and then doing a double take.</p><h2 id="the-nomination" tabindex="-1">The Nomination <a class="header-anchor" href="#the-nomination" aria-label="Permalink to &quot;The Nomination&quot;">​</a></h2><p>I didn&#39;t nominate it myself. A community member named <a href="https://users.rust-lang.org/u/nik-rev" target="_blank" rel="noreferrer">Nik Revenco</a> posted on the Rust Users Forum and made the case for farben better than I probably would have:</p><blockquote><p><em>&quot;This is a highly underrated library that has a very nice syntax for printing to the standard output. Fantastic for scripts.&quot;</em></p></blockquote><p>He listed out the compile-time feature, the zero-dependency design, the prelude, the markdown macros, the bleed variants, all things I built described back to me by someone who found them useful. That felt really good.</p><p>Thank you so, so much, Nik.</p><h2 id="what-this-means" tabindex="-1">What this means <a class="header-anchor" href="#what-this-means" aria-label="Permalink to &quot;What this means&quot;">​</a></h2><p>When I started Farben, it was because I was tired of writing <code>\\x1b[31m</code> or <code>.bold().red()</code> and wanted something that looked like <code>[bold red]</code>. That was the whole idea. I didn&#39;t expect it to go anywhere in particular.</p><p>The star count doubled overnight because of the nomination. People are opening issues, asking questions, trying it out. It turns out the Rust community really does appreciate libraries that stay small, stay focused, and don&#39;t drag in half of crates.io as dependencies. I didn&#39;t even realize this until just last Sunday!</p><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><p>Farben isn&#39;t done. The API has been stable this last couple of versions and the path to 1.0 is clearer than ever. There&#39;s still work to do: more testing, more polish, more feedback, more features, more speed, more everything.</p><p>And if you&#39;re here because of TWiR: welcome! Feel free to open an issue, try the <code>compile</code> feature, break things, and tell me what you think.</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> farben</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">prelude</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cprintln!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[bold red]&lt;3[/] [bold green]Thanks for the love![/] 🦀&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Make great things with Farben.</p><p>Cheers, RazkarStudio</p>`,19)])])}const c=t(n,[["render",o]]);export{k as __pageData,c as default};
